<?php declare(strict_types=1);
namespace SkyFi\System\Controllers;
use SkyFi\Shared\Exceptions\ValidationException;
use SkyFi\Shared\Http\{ApiResponse,Request,Response};
use SkyFi\System\Services\{BrandingAssetService,SystemAdministrationService,SystemConfigurationProvider};
use SkyFi\System\Validators\SystemValidator;
final class BrandingController extends SystemBaseController { public function __construct(private readonly SystemAdministrationService $service, private readonly BrandingAssetService $assets, private readonly SystemConfigurationProvider $config, private readonly SystemValidator $validator, \SkyFi\Rbac\Middleware\RequirePermissionMiddleware $p){parent::__construct($p);} public function show(Request $r): Response { $this->user($r,'system.view'); $d=$this->service->branding->first(); return ApiResponse::resource('branding',(string)$d['id'],$d); } public function update(Request $r): Response { $u=$this->user($r,'system.update'); $d=$this->service->updateBranding($r->body(),$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('branding',(string)$d['id'],$d); } public function upload(Request $r): Response { $u=$this->user($r,'system.update'); $files=$r->files(); $file=$files['file'] ?? null; if (!is_array($file)) throw new ValidationException([['code'=>'validation_error','detail'=>'A file upload is required.','source'=>['pointer'=>'/file']]]); $type=(string)($r->body()['type'] ?? $r->query()['type'] ?? 'logo'); if (!in_array($type,['logo','favicon','login_background'],true)) $type='logo'; $this->validator->asset($file,$this->config->fileUploadLimits()); $path=$this->assets->store($file,$type); $field=$type==='login_background'?'login_background_path':$type.'_path'; $d=$this->service->updateBranding([$field=>$path],$u,$r->ipAddress(),$r->userAgent()); return new Response(201,['data'=>['type'=>'branding-assets','id'=>$type,'attributes'=>['path'=>$path,'branding'=>$d]]]); }}
